import React, { useState } from "react";
import { Routes, Route, Navigate, useLocation, useNavigate } from "react-router-dom";
import DashboardPage from "../DashboardPage/DashboardPage";
import PriceManagementPage from "../PriceManagementPage/PriceManagementPage";
import InventoryMonitoringPage from "../InventoryMonitoringPage/InventoryMonitoringPage";
import ReportsAndAnalyticsPage from "../ReportsAndAnalyticsPage/ReportsAndAnalyticsPage";
import AlertsManagementPage from "../AlertsManagement/AlertsManagementPage";
import UserManagementPage from "../UserManagementPage/UserManagementPage";
import HelpCenterPage from "../HelpCenterPage/HelpCenterPage";
import Sidebar from "./Sidebar";
import TopBar from "./TopBar"; // TopBar'ı da ekleyelim

const MainLayout: React.FC = () => {
    const location = useLocation();
    const navigate = useNavigate();
    const [activeLink, setActiveLink] = useState('dashboard'); // Varsayılan aktif link

    const handleLinkClick = (link: string) => {
        setActiveLink(link);
        // Link'e göre yönlendirme yap
        switch (link) {
            case 'realtime':
                navigate('/prices');
                break;
            case 'inventory':
                navigate('/inventory');
                break;
            case 'alerts':
                navigate('/alerts');
                break;
            case 'analytics':
                navigate('/reports');
                break;
            case 'settings':
                navigate('/users'); // Örnek olarak /users'a yönlendirdim
                break;
            case 'help':
                navigate('/help');
                break;
            default:
                navigate('/dashboard');
        }
    };

    return (
        <div style={{ display: "flex" }}>
            <Sidebar activeLink={activeLink} onLinkClick={handleLinkClick} />
            <div style={{ flex: 1, padding: 20 }}>
                <TopBar
                    onSearch={(searchTerm) => console.log("Search:", searchTerm)} // Örnek fonksiyon
                    onLogout={() => navigate('/login')} // Örnek fonksiyon
                    onSettings={() => console.log("Settings clicked")} // Örnek fonksiyon
                />
                <Routes location={location} key={location.pathname}>
                    <Route path="/dashboard" element={<DashboardPage />} />
                    <Route path="/prices" element={<PriceManagementPage />} />
                    <Route path="/inventory" element={<InventoryMonitoringPage />} />
                    <Route path="/reports" element={<ReportsAndAnalyticsPage />} />
                    <Route path="/alerts" element={<AlertsManagementPage />} />
                    <Route path="/users" element={<UserManagementPage />} />
                    <Route path="/help" element={<HelpCenterPage />} />
                    <Route path="*" element={<Navigate to="/dashboard" />} />
                </Routes>
            </div>
        </div>
    );
};

export default MainLayout;
